    uint32_t offset = field & 31u;
    uint32_t width = (field >> 16) & 127u;
    if (width == 0)
      return 0u;
    uint32_t mask = width >= 32 ? ~0u : ((1u << width) - 1u);
    return (base >> offset) & mask;
